import{Handle}from"../primitives/Handle.js";import{random}from"../tools/random.js";class Relay extends Handle{constructor(){super(),this.select={one:h=>[random.oneOf(h)],some:h=>random.some(h),all:h=>[h]}}onblamready(){super.onblamready(),this.handlerElems=[...this.querySelectorAll(":scope > *")]}handle(event){if(random.chance(this.chance)){this.select[this.mode](this.handlerElems).forEach(h=>{h.handle(event)})}}get mode(){let value=this.getAttribute("mode");return["one","some","all"].find(v=>v===value)||"all"}set mode(value){this.setAttribute("mode",value)}disconnectedCallback(){this.unlisten()}}export{Relay};